    "ExperimentName": "Synthesis of CsPbBr₃ Nanocubes at Room Temperature",
    "Materials": [
        { "MaterialId": "M1", "Name": "Cesium bromide", "Formula": "CsBr", "Amount": "0.4", "Unit": "mmol", "Purity": "99%", "State": "Solid" },
