        { "MaterialId": "M3", "Name": "Dimethylformamide", "Formula": "C3H7NO", "Amount": "10", "Unit": "mL", "Purity": "99%", "State": "Liquid" },
        { "MaterialId": "M4", "Name": "Oleic acid", "Formula": "C18H34O2", "Amount": "1", "Unit": "mL", "Purity": "90%", "State": "Liquid" },
        { "MaterialId": "M5", "Name": "Oleylamine", "Formula": "C18H37N", "Amount": "0.5", "Unit": "mL", "Purity": "80%", "State": "Liquid" },
        { "MaterialId": "M6", "Name": "Chloroform", "Formula": "CHCl3", "Amount": "10", "Unit": "mL", "Purity": "99%", "State": "Liquid" }
    ],
    "Containers": [
        { "ContainerId": "C1", "Name": "Beaker", "Capacity": "50", "Unit": "mL", "MaterialOfConstruction": "Glass", "Shape": "Cylindrical", "HeatResistant": "Yes", "PressureRating": "NA" },
        { "ContainerId": "C2", "Name": "Flask", "Capacity": "100", "Unit": "mL", "MaterialOfConstruction": "Glass", "Shape": "Conical", "HeatResistant": "Yes", "PressureRating": "NA" }
    ],
    "Equipments": [
        { "EquipmentId": "E1", "Name": "Magnetic Stirrer", "Parameters": { "Speed": "500-2000 rpm" } },
        { "EquipmentId": "E2", "Name": "Centrifuge", "Parameters": { "Speed": "10000 rpm" } }
    ],
    "RobotWorkflow": [
        {
            "StepId": "1",
            "Description": "Dissolve CsBr and PbBr₂ in DMF under stirring at room temperature.",
            "Actions": [
                { "ActionType": "pick_container_with_material", "ContainerId": "C1", "MaterialId": "M1", "EquipmentId": null },
                { "ActionType": "pick_container_with_material", "ContainerId": "C1", "MaterialId": "M2", "EquipmentId": null },
                { "ActionType": "pick_container_with_material", "ContainerId": "C1", "MaterialId": "M3", "EquipmentId": null },
                { "ActionType": "place_container_into_equipment", "ContainerId": "C1", "MaterialId": null, "EquipmentId": "E1" }
            ],
            "Dependencies": [],
            "StepOutput": {
                "ContainerId": "C1",
                "Contents": [
                    { "MaterialId": "M1", "Amount": "0.4", "Unit": "mmol" },
                    { "MaterialId": "M2", "Amount": "0.4", "Unit": "mmol" },
                    { "MaterialId": "M3", "Amount": "10", "Unit": "mL" }
                ]
            }
        },
        {
            "StepId": "2",
            "Description": "Add oleic acid and oleylamine to the mixture.",
            "Actions": [
                { "ActionType": "pick_container_with_material", "ContainerId": "C1", "MaterialId": "M4", "EquipmentId": null },
                { "ActionType": "pick_container_with_material", "ContainerId": "C1", "MaterialId": "M5", "EquipmentId": null }
            ],
            "Dependencies": ["1"],
            "StepOutput": {
                "ContainerId": "C1",
                "Contents": [
                    { "MaterialId": "M4", "Amount": "1", "Unit": "mL" },
                    { "MaterialId": "M5", "Amount": "0.5", "Unit": "mL" },
                    { "MaterialId": "M1", "Amount": "0.4", "Unit": "mmol" },
                    { "MaterialId": "M2", "Amount": "0.4", "Unit": "mmol" },
                    { "MaterialId": "M3", "Amount": "10", "Unit": "mL" }
                ]
            }
        },
        {
            "StepId": "3",
            "Description": "Inject the precursor solution into chloroform under fast stirring.",
            "Actions": [
                { "ActionType": "pick_container_with_material", "ContainerId": "C1", "MaterialId": null, "EquipmentId": null },
                { "ActionType": "pick_container_with_material", "ContainerId": "C2", "MaterialId": "M6", "EquipmentId": null },
                { "ActionType": "place_container_into_equipment", "ContainerId": "C2", "MaterialId": "M6", "EquipmentId": "E1" }
            ],
            "Dependencies": ["2"],
            "StepOutput": {
                "ContainerId": "C2",
                "Contents": [
                    { "MaterialId": "M6", "Amount": "10", "Unit": "mL" },
                    { "MaterialId": "N1", "Name": "CsPbBr₃ Nanocubes", "Amount": "Synthesized", "Unit": "Colloidal solution" }
                ]
            }
        },
        {
            "StepId": "4",
            "Description": "Centrifuge the solution to collect the CsPbBr₃ nanocubes.",
            "Actions": [
                { "ActionType": "pick_container_with_material", "ContainerId": "C2", "MaterialId": "N1", "EquipmentId": null },
                { "ActionType": "place_container_into_equipment", "ContainerId": "C2", "MaterialId": "N1", "EquipmentId": "E2" }
            ],
            "Dependencies": ["3"],
            "StepOutput": {
                "ContainerId": "C2",
                "Contents": [
                    { "MaterialId": "N1", "Name": "CsPbBr₃ Nanocubes", "Amount": "Purified", "Unit": "Solid" }
                ]
            }
        }
    ]
}
